import { ethers } from "ethers";

const ERC20_ABI = [
  "function approve(address spender, uint256 amount) external returns (bool)",
  "function allowance(address owner, address spender) external view returns (uint256)",
  "function balanceOf(address account) external view returns (uint256)",
  "function decimals() external view returns (uint8)",
  "function symbol() external view returns (string)",
  "function name() external view returns (string)"
];

const ROUTER_ABI = [
  "function swapExactTokensForTokens(uint256 amountIn,uint256 amountOutMin,address[] calldata path,address to,uint256 deadline) external returns (uint256[] memory amounts)",
  "function getAmountsOut(uint256 amountIn,address[] calldata path) external view returns (uint256[] memory amounts)"
];

const MAX_UINT256 = ethers.MaxUint256;

export class TokenSwapDApp {
  constructor({
    provider,
    signer,
    routerAddress,
    routerAbi = ROUTER_ABI,
    erc20Abi = ERC20_ABI
  }) {
    this.provider = provider;
    this.signer = signer;
    this.routerAddress = routerAddress;
    this.routerAbi = routerAbi;
    this.erc20Abi = erc20Abi;
    this.router = new ethers.Contract(routerAddress, routerAbi, signer || provider);
  }

  static async fromBrowserProvider(routerAddress, routerAbi = ROUTER_ABI, erc20Abi = ERC20_ABI) {
    if (!window.ethereum) throw new Error("No injected wallet found");
    const provider = new ethers.BrowserProvider(window.ethereum);
    await provider.send("eth_requestAccounts", []);
    const signer = await provider.getSigner();
    return new TokenSwapDApp({ provider, signer, routerAddress, routerAbi, erc20Abi });
  }

  async connectWallet() {
    if (!this.provider || !(this.provider instanceof ethers.BrowserProvider)) {
      throw new Error("BrowserProvider required for wallet connection");
    }
    await this.provider.send("eth_requestAccounts", []);
    this.signer = await this.provider.getSigner();
    this.router = new ethers.Contract(this.routerAddress, this.routerAbi, this.signer);
    return this.signer.getAddress();
  }

  getTokenContract(tokenAddress, withSigner = true) {
    const runner = withSigner && this.signer ? this.signer : this.provider;
    return new ethers.Contract(tokenAddress, this.erc20Abi, runner);
  }

  async getAccount() {
    if (!this.signer) throw new Error("Wallet not connected");
    return this.signer.getAddress();
  }

  async getTokenMetadata(tokenAddress) {
    const token = this.getTokenContract(tokenAddress, false);
    const [name, symbol, decimals] = await Promise.all([
      token.name(),
      token.symbol(),
      token.decimals()
    ]);
    return { name, symbol, decimals: Number(decimals) };
  }

  async getTokenBalance(tokenAddress, account) {
    const token = this.getTokenContract(tokenAddress, false);
    const [balance, decimals] = await Promise.all([
      token.balanceOf(account),
      token.decimals()
    ]);
    return {
      raw: balance,
      formatted: ethers.formatUnits(balance, decimals),
      decimals: Number(decimals)
    };
  }

  async getAllowance(tokenAddress, owner, spender = this.routerAddress) {
    const token = this.getTokenContract(tokenAddress, false);
    return token.allowance(owner, spender);
  }

  async isMaxApproved(tokenAddress, owner, spender = this.routerAddress) {
    const allowance = await this.getAllowance(tokenAddress, owner, spender);
    return allowance === MAX_UINT256;
  }

  async approveMax(tokenAddress, spender = this.routerAddress) {
    if (!this.signer) throw new Error("Wallet not connected");
    const token = this.getTokenContract(tokenAddress, true);
    const tx = await token.approve(spender, MAX_UINT256);
    const receipt = await tx.wait();
    return { tx, receipt, approvedAmount: MAX_UINT256 };
  }

  async ensureApproval(tokenAddress, requiredAmount, owner, spender = this.routerAddress) {
    const allowance = await this.getAllowance(tokenAddress, owner, spender);
    if (allowance >= requiredAmount) {
      return { alreadyApproved: true, allowance };
    }
    const approval = await this.approveMax(tokenAddress, spender);
    return {
      alreadyApproved: false,
      allowanceBefore: allowance,
      allowanceAfter: MAX_UINT256,
      approval
    };
  }

  async getAmountsOut(amountIn, path) {
    const amounts = await this.router.getAmountsOut(amountIn, path);
    return amounts;
  }

  async quoteSwap({
    tokenIn,
    tokenOut,
    amountIn,
    slippageBps = 50
  }) {
    const path = [tokenIn, tokenOut];
    const amounts = await this.getAmountsOut(amountIn, path);
    const amountOut = amounts[amounts.length - 1];
    const amountOutMin = amountOut - (amountOut * BigInt(slippageBps)) / 10000n;
    return {
      path,
      amountIn,
      amountOut,
      amountOutMin,
      slippageBps
    };
  }

  async swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn,
    amountOutMin,
    to,
    deadlineSeconds = 1200,
    autoApprove = true
  }) {
    if (!this.signer) throw new Error("Wallet not connected");
    const recipient = to || (await this.getAccount());
    const owner = await this.getAccount();

    if (autoApprove) {
      await this.ensureApproval(tokenIn, amountIn, owner, this.routerAddress);
    }

    const path = [tokenIn, tokenOut];
    const deadline = Math.floor(Date.now() / 1000) + deadlineSeconds;
    const tx = await this.router.swapExactTokensForTokens(
      amountIn,
      amountOutMin,
      path,
      recipient,
      deadline
    );
    const receipt = await tx.wait();

    return {
      tx,
      receipt,
      path,
      amountIn,
      amountOutMin,
      to: recipient,
      deadline
    };
  }

  async swapWithQuote({
    tokenIn,
    tokenOut,
    amountIn,
    slippageBps = 50,
    to,
    deadlineSeconds = 1200,
    autoApprove = true
  }) {
    const quote = await this.quoteSwap({ tokenIn, tokenOut, amountIn, slippageBps });
    const result = await this.swapExactTokensForTokens({
      tokenIn,
      tokenOut,
      amountIn,
      amountOutMin: quote.amountOutMin,
      to,
      deadlineSeconds,
      autoApprove
    });
    return { quote, result };
  }

  async parseAmount(tokenAddress, amount) {
    const token = this.getTokenContract(tokenAddress, false);
    const decimals = await token.decimals();
    return ethers.parseUnits(String(amount), decimals);
  }

  async formatAmount(tokenAddress, amount) {
    const token = this.getTokenContract(tokenAddress, false);
    const decimals = await token.decimals();
    return ethers.formatUnits(amount, decimals);
  }
}

export async function createSwapInterface({
  routerAddress,
  tokenInAddress,
  tokenOutAddress,
  amountInHuman,
  slippageBps = 50
}) {
  const app = await TokenSwapDApp.fromBrowserProvider(routerAddress);
  const account = await app.getAccount();
  const amountIn = await app.parseAmount(tokenInAddress, amountInHuman);

  const approvalStatus = await app.ensureApproval(tokenInAddress, amountIn, account);
  const quote = await app.quoteSwap({
    tokenIn: tokenInAddress,
    tokenOut: tokenOutAddress,
    amountIn,
    slippageBps
  });

  return {
    app,
    account,
    approvalStatus,
    quote,
    execute: async () =>
      app.swapExactTokensForTokens({
        tokenIn: tokenInAddress,
        tokenOut: tokenOutAddress,
        amountIn,
        amountOutMin: quote.amountOutMin,
        to: account,
        autoApprove: false
      })
  };
}